/**
 * Spatial rendering context for <model>
 *
 * Manages the Three.js scene, camera, canvas, blit pipeline, view offset,
 * scroll tracking, resize handling, intersection observer, background color,
 * environment map, render loop, orbit controls, and entity transform.
 */

import {
	Vector2,
	Scene,
	PerspectiveCamera,
	Group,
	EquirectangularReflectionMapping
} from 'three';
import { HDRLoader } from 'three/examples/jsm/loaders/HDRLoader.js';
import { createDefaultEnvironmentMap } from './environment-map.js';
import { registerElement, unregisterElement } from './shared-renderer.js';
import {
	calculateDefaultTransform,
	extractScaleFromMatrix,
	buildTransformMatrix,
	calculateNonOrbitFinalZ,
	applyMatrixToObject3D,
	resetOrbitState,
	enableOrbitControls,
	disableOrbitControls,
	CSS_PIXELS_PER_CM,
	onPointerDown as orbitPointerDown,
	onPointerMove as orbitPointerMove,
	onPointerUp as orbitPointerUp,
	updateOrbitPhysics,
	updateEntityTransformFromOrbit
} from './entity-transform.js';
import * as _unifiedFrustum from './unified-frustum.js';
void _unifiedFrustum;

/**
 * Shared HDR loader instance
 */
const sharedHDRLoader = new HDRLoader();

/**
 * Spatial camera constants
 */
const CAMERA_DISTANCE = 0.5;

/**
 * Reusable Three.js objects (avoids allocations in frequently called functions)
 */
const _rendererSize = new Vector2();

/**
 * Shared IntersectionObserver for visibility tracking
 */
const spatialIntersectionObserver = new IntersectionObserver((entries) => {
	for (const entry of entries) {
		const ctx = spatialContextMap.get(entry.target);
		if (ctx) {
			ctx.isVisible = entry.isIntersecting;
		}
	}
}, { threshold: 0 });

/**
 * Map from elements to their spatial context state
 * @type {WeakMap<HTMLElement, Object>}
 */
const spatialContextMap = new WeakMap();

/**
 * Get the spatial context for an element.
 */
export function getSpatialContext(element) {
	return spatialContextMap.get(element);
}

/**
 * Create a spatial context state object.
 * Does NOT set up Three.js or observers — call initSpatialContext for that.
 */
export function createSpatialContext(element) {
	const state = {
		// Three.js core
		scene: null,
		camera: null,
		canvas: null,
		blitCtx: null,

		// Groups
		portalGroup: null,
		pivotGroup: null,

		// Observers
		resizeObserver: null,

		// State
		isVisible: false,
		entityTransform: new DOMMatrixReadOnly(),
		userSetEntityTransform: false,

		// Bounding box
		boundingBoxCenter: new DOMPointReadOnly(0, 0, 0, 1),
		boundingBoxExtents: new DOMPointReadOnly(0, 0, 0, 0),
		modelSize: null,

		// Orbit control state
		isDragging: false,
		orbitQuaternion: { x: 0, y: 0, z: 0, w: 1 },
		yawVelocity: 0,
		pitchVelocity: 0,
		lastPointerX: 0,
		lastPointerY: 0,
		lastMoveTime: 0,

		// Orbit control constants
		orbitDamping: 0.95,
		pitchReturnSpeed: 0.05,
		dragSensitivity: 0.005,

		// Bound event handlers
		boundPointerDown: null,
		boundPointerMove: null,
		boundPointerUp: null,

		// Environment map
		hdrLoader: sharedHDRLoader,
		environmentTexture: null,
		environmentMapReady: Promise.resolve(),
		environmentMapReadyResolve: null,
		environmentMapVersion: 0,

		// When true, the next render resolves the element's ready promise
		pendingFirstRender: false,

		// Per-element callbacks (set during initElement)
		onFirstRender: null,   // called after the first rendered frame
		onFrameTick: null,     // called each frame before render (animation tick)
		getStageModeForElement: null, // returns the current stage mode string
	};

	// Create bound event handlers for orbit controls
	state.boundPointerDown = (e) => {
		if (state.getStageModeForElement?.(element) !== 'orbit') return;
		orbitPointerDown(state, e);
	};
	state.boundPointerMove = (e) => {
		if (state.getStageModeForElement?.(element) !== 'orbit') return;
		orbitPointerMove(state, e);
	};
	state.boundPointerUp = (e) => orbitPointerUp(state, e);

	spatialContextMap.set(element, state);
	return state;
}

/**
 * Initialize the spatial context — sets up Three.js, observers, registers render loop.
 */
export function initSpatialContext(element, state) {
	state.canvas = document.createElement('canvas');
	state.canvas.className = '__model-element-fallback-canvas-f7a9c3e1__';
	state.canvas.style.width = '100%';
	state.canvas.style.height = '100%';
	state.canvas.style.display = 'block';
	element.appendChild(state.canvas);

	state.blitCtx = state.canvas.getContext('2d');
	state.blitCtx.imageSmoothingEnabled = false;

	const width = element.clientWidth || 400;
	const height = element.clientHeight || 300;

	const dpr = window.devicePixelRatio;
	state.canvas.width = Math.round(width * dpr);
	state.canvas.height = Math.round(height * dpr);

	state.scene = new Scene();
	state.scene.background = null;
	state.canvas.style.background = 'Canvas';
	state.scene.environment = createDefaultEnvironmentMap();

	const fov = calculateStandardFOV(element);

	state.camera = new PerspectiveCamera(fov, width / height, CAMERA_DISTANCE * 0.5, 100 + CAMERA_DISTANCE);
	state.camera.position.set(0, 0, CAMERA_DISTANCE);

	state.resizeObserver = new ResizeObserver(() => handleSpatialResize(element, state));
	state.resizeObserver.observe(element);

	spatialIntersectionObserver.observe(element);

	registerElement(element, (renderer) => renderFrame(element, state, renderer));
}

/**
 * Destroy / cleanup a spatial context.
 */
export function destroySpatialContext(element, state) {
	unregisterElement(element);
	disableOrbitControls(element, state);
	spatialIntersectionObserver.unobserve(element);

	if (state.resizeObserver) {
		state.resizeObserver.disconnect();
		state.resizeObserver = null;
	}

	if (state.environmentTexture) {
		state.environmentTexture.dispose();
		state.environmentTexture = null;
	}

	state.boundingBoxCenter = new DOMPointReadOnly(0, 0, 0, 1);
	state.boundingBoxExtents = new DOMPointReadOnly(0, 0, 0, 0);
	state.modelSize = null;

	if (state.portalGroup && state.scene) {
		state.scene.remove(state.portalGroup);
		state.portalGroup = null;
		state.pivotGroup = null;
	}

	if (state.canvas) {
		state.canvas.remove();
		state.canvas = null;
	}

	state.blitCtx = null;
	state.scene = null;
	state.camera = null;

	spatialContextMap.delete(element);
}

/**
 * Add a 3D object to the scene's portal/pivot groups and update bounding box.
 */
export function addObjectToScene(element, state, object3d, center, size) {
	if (!state || !state.scene) return;

	if (state.portalGroup) {
		state.scene.remove(state.portalGroup);
	}

	state.portalGroup = new Group();
	state.pivotGroup = new Group();

	state.scene.add(state.portalGroup);
	state.portalGroup.add(state.pivotGroup);
	state.pivotGroup.add(object3d);

	state.modelSize = size;
	state.boundingBoxCenter = new DOMPointReadOnly(center.x, center.y, center.z, 1);
	state.boundingBoxExtents = new DOMPointReadOnly(size.x, size.y, size.z, 0);

	state.pivotGroup.position.set(0, 0, 0);
	state.pivotGroup.rotation.set(0, 0, 0);
	state.pivotGroup.scale.set(1, 1, 1);

	const stageMode = state.getStageModeForElement?.(element) ?? 'none';
	const matrix = calculateDefaultTransform(element, size, center, stageMode === 'orbit');
	state.entityTransform = matrix;
	state.userSetEntityTransform = false;
	applyEntityTransform(element, state);

	resetOrbitState(state);
}

/**
 * Resize handler.
 */
export function handleSpatialResize(element, state) {
	if (!state) return;

	const width = element.clientWidth;
	const height = element.clientHeight;

	if (width === 0 || height === 0 || !state.canvas || !state.camera) return;

	const dpr = window.devicePixelRatio;
	const newWidth = Math.round(width * dpr);
	const newHeight = Math.round(height * dpr);

	if (state.canvas.width === newWidth && state.canvas.height === newHeight) return;

	state.canvas.width = newWidth;
	state.canvas.height = newHeight;
	updateStandardCamera(element, state);
	if (state.modelSize && !state.userSetEntityTransform) {
		const stageMode = state.getStageModeForElement?.(element) ?? 'none';
		const matrix = calculateDefaultTransform(element, state.modelSize, state.boundingBoxCenter, stageMode === 'orbit');
		state.entityTransform = matrix;
		applyEntityTransform(element, state);
	}
}

/**
 * Update the scene background color from element's computed styles.
 */
export function updateSpatialBackgroundColor(element, state) {
	if (!state?.scene) return;
	const style = getComputedStyle(element);
	if (state.canvas) {
		const bg = style.backgroundColor;
		const color = (bg && bg !== 'transparent' && bg !== 'rgba(0, 0, 0, 0)') ? bg : 'Canvas';
		state.canvas.style.background = `linear-gradient(${color}, ${color}), canvas`;
	}
}

/**
 * Handle environment map changes.
 */
export function handleSpatialEnvironmentMap(element, state, url) {
	if (!state) return;

	state.environmentMapVersion++;
	const version = state.environmentMapVersion;

	if (!url) {
		if (state.environmentTexture) {
			state.environmentTexture.dispose();
			state.environmentTexture = null;
		}
		if (state.scene) {
			state.scene.environment = createDefaultEnvironmentMap();
		}
		state.environmentMapReady = Promise.resolve();
		state.environmentMapReadyResolve = null;
		return;
	}

	state.environmentMapReady = new Promise((resolve, reject) => {
		state.environmentMapReadyResolve = resolve;
		state.hdrLoader.load(
			url,
			(texture) => {
				if (version !== state.environmentMapVersion) {
					texture.dispose();
					return;
				}
				if (state.environmentTexture) {
					state.environmentTexture.dispose();
				}
				texture.mapping = EquirectangularReflectionMapping;
				state.environmentTexture = texture;
				if (state.scene) {
					state.scene.environment = texture;
				}
				element.dispatchEvent(new Event('iblload'));
				state.environmentMapReadyResolve = null;
				resolve();
			},
			undefined,
			(error) => {
				if (version !== state.environmentMapVersion) return;
				console.error('Failed to load environment map:', error);
				element.dispatchEvent(new CustomEvent('error', { detail: error }));
				state.environmentMapReadyResolve = null;
				reject(error);
			}
		);
	});
}

/**
 * Handle stage mode changes.
 */
export function setSpatialStageMode(element, state, mode) {
	if (!state) return;

	if (mode === 'orbit') {
		if (state.modelSize) {
			const matrix = calculateDefaultTransform(element, state.modelSize, state.boundingBoxCenter, true);
			state.entityTransform = matrix;
			applyEntityTransform(element, state);
		}
		resetOrbitState(state);
		enableOrbitControls(element, state);
	} else {
		disableOrbitControls(element, state);
		if (state.modelSize) {
			const baseTransform = calculateDefaultTransform(element, state.modelSize, state.boundingBoxCenter, false);
			const scale = extractScaleFromMatrix(baseTransform);
			const finalZ = calculateNonOrbitFinalZ(state.modelSize, scale);

			state.entityTransform = buildTransformMatrix(scale, finalZ, state.orbitQuaternion, state.boundingBoxCenter);
			applyEntityTransform(element, state);
		}
	}
}

/**
 * Get the entity transform.
 */
export function getSpatialEntityTransform(state) {
	if (!state) return new DOMMatrixReadOnly();
	return new DOMMatrixReadOnly(state.entityTransform.toFloat64Array());
}

/**
 * Set the entity transform (rejected in orbit mode).
 */
export function setSpatialEntityTransform(element, state, value) {
	if (!state) return;
	const stageMode = state.getStageModeForElement?.(element) ?? 'none';
	if (stageMode === 'orbit') return;

	if (value instanceof DOMMatrix || value instanceof DOMMatrixReadOnly) {
		state.entityTransform = new DOMMatrix(value.toFloat64Array());
		state.userSetEntityTransform = true;
		applyEntityTransform(element, state);
	}
}

// ---- Internal helpers ----

function calculateStandardFOV(element) {
	if (element.clientHeight <= 0) return 50;
	const elementHeightM = element.clientHeight / CSS_PIXELS_PER_CM / 100;
	return 2 * Math.atan(elementHeightM / (2 * CAMERA_DISTANCE)) * (180 / Math.PI);
}

function updateStandardCamera(element, state) {
	if (!state?.camera) return;
	const width = element.clientWidth;
	const height = element.clientHeight;
	if (width === 0 || height === 0) return;
	state.camera.aspect = width / height;
	state.camera.fov = calculateStandardFOV(element);
	state.camera.updateProjectionMatrix();
}

export function applyEntityTransform(element, state) {
	if (!state?.pivotGroup) return;
	applyMatrixToObject3D(state.entityTransform, state.pivotGroup);
}

function renderFrame(element, state, renderer) {
	if (!state || !renderer) return;

	// Let the owner tick (animations, etc.)
	state.onFrameTick?.(element, renderer);

	if (state.pendingFirstRender && state.scene && state.camera) {
		const stageMode = state.getStageModeForElement?.(element) ?? 'none';
		if (stageMode === 'orbit' && state.pivotGroup) {
			updateOrbitPhysics(state);
			updateEntityTransformFromOrbit(state, () => applyEntityTransform(element, state));
		}

		renderAndBlit(element, state, renderer);

		state.pendingFirstRender = false;
		state.onFirstRender?.(element);
		return;
	}

	const stageMode = state.getStageModeForElement?.(element) ?? 'none';
	if (stageMode === 'orbit' && state.pivotGroup) {
		updateOrbitPhysics(state);
		updateEntityTransformFromOrbit(state, () => applyEntityTransform(element, state));
	}

	if (!state.isVisible || !state.scene || !state.camera) {
		return;
	}

	renderAndBlit(element, state, renderer);
}

function renderAndBlit(element, state, renderer) {
	if (!state || !renderer || !state.canvas || !state.blitCtx || !state.scene || !state.camera) return;

	const width = state.canvas.width;
	const height = state.canvas.height;

	if (width === 0 || height === 0) return;

	const dpr = renderer.getPixelRatio();
	const cssWidth = width / dpr;
	const cssHeight = height / dpr;

	renderer.getSize(_rendererSize);
	const currentDevWidth = Math.round(_rendererSize.x * dpr);
	const currentDevHeight = Math.round(_rendererSize.y * dpr);
	if (currentDevWidth !== width || currentDevHeight !== height) {
		renderer.setSize(cssWidth, cssHeight, false);
	}

	renderer.render(state.scene, state.camera);

	const srcWidth = renderer.domElement.width;
	const srcHeight = renderer.domElement.height;
	state.blitCtx.clearRect(0, 0, width, height);
	state.blitCtx.drawImage(renderer.domElement, 0, 0, srcWidth, srcHeight, 0, 0, width, height);
}
