import {
	DataTexture,
	RGBAFormat,
	FloatType,
	EquirectangularReflectionMapping
} from 'three';

let defaultEnvironmentMap = null;

const ENV_DATA = '';
const SH_BASIS = [
	(x, y, z) => 0.282095,
	(x, y, z) => 0.488603 * y,
	(x, y, z) => 0.488603 * z,
	(x, y, z) => 0.488603 * x,
	(x, y, z) => 1.092548 * x * y,
	(x, y, z) => 1.092548 * y * z,
	(x, y, z) => 0.315392 * (3 * z * z - 1),
	(x, y, z) => 1.092548 * x * z,
	(x, y, z) => 0.546274 * (x * x - y * y),
	(x, y, z) => 0.590044 * y * (3 * x * x - y * y),
	(x, y, z) => 2.890611 * x * y * z,
	(x, y, z) => 0.457046 * y * (5 * z * z - 1),
	(x, y, z) => 0.373176 * z * (5 * z * z - 3),
	(x, y, z) => 0.457046 * x * (5 * z * z - 1),
	(x, y, z) => 1.445306 * (x * x - y * y) * z,
	(x, y, z) => 0.590044 * x * (x * x - 3 * y * y)
];

function decodeCompressed(b64) {
	const binary = atob(b64);
	const bytes = new Uint8Array(binary.length);
	for (let i = 0; i < binary.length; i++) bytes[i] = binary.charCodeAt(i);
	const buf = bytes.buffer;
	const header = new Uint32Array(buf, 0, 4);
	const shCount = header[0];
	const lobeCount = header[1];
	const mono = header[2] === 1;
	const floats = new Float32Array(buf, 16);
	let offset = 0;
	const sh = [];
	for (let i = 0; i < shCount; i++) {
		if (mono) {
			const v = floats[offset++];
			sh.push([v, v, v]);
		} else {
			sh.push([floats[offset++], floats[offset++], floats[offset++]]);
		}
	}
	const lobes = [];
	for (let i = 0; i < lobeCount; i++) {
		const theta = floats[offset++];
		const phi = floats[offset++];
		let color;
		if (mono) {
			const v = floats[offset++];
			color = [v, v, v];
		} else {
			color = [floats[offset++], floats[offset++], floats[offset++]];
		}
		const radius = floats[offset++];
		lobes.push({ theta, phi, color, radius });
	}
	return { sh, lobes };
}

function reconstructHDR(data, width, height) {
	const pixels = new Float32Array(width * height * 4);
	const { sh, lobes } = data;

	const lobeDirs = lobes.map(l => ({
		x: Math.sin(l.phi) * Math.sin(l.theta),
		y: Math.cos(l.phi),
		z: Math.sin(l.phi) * Math.cos(l.theta),
		color: l.color,
		invR2: 1 / (2 * l.radius * l.radius)
	}));

	for (let j = 0; j < height; j++) {
		const v = (j + 0.5) / height;
		const phi = (1 - v) * Math.PI;
		const sinPhi = Math.sin(phi);
		const cosPhi = Math.cos(phi);

		for (let i = 0; i < width; i++) {
			const u = (i + 0.5) / width;
			const theta = (u - 0.5) * 2 * Math.PI;
			const x = sinPhi * Math.sin(theta);
			const y = cosPhi;
			const z = sinPhi * Math.cos(theta);

			let r = 0, g = 0, b = 0;

			for (let k = 0; k < sh.length; k++) {
				const basis = SH_BASIS[k](x, y, z);
				r += sh[k][0] * basis;
				g += sh[k][1] * basis;
				b += sh[k][2] * basis;
			}

			for (const lobe of lobeDirs) {
				const dot = x * lobe.x + y * lobe.y + z * lobe.z;
				const angle = Math.acos(Math.min(1, Math.max(-1, dot)));
				const falloff = Math.exp(-(angle * angle) * lobe.invR2);
				r += lobe.color[0] * falloff;
				g += lobe.color[1] * falloff;
				b += lobe.color[2] * falloff;
			}

			const idx = (j * width + i) * 4;
			pixels[idx] = Math.max(0, r);
			pixels[idx + 1] = Math.max(0, g);
			pixels[idx + 2] = Math.max(0, b);
			pixels[idx + 3] = 1;
		}
	}

	return pixels;
}

export function createDefaultEnvironmentMap() {
	if (defaultEnvironmentMap) return defaultEnvironmentMap;

	const width = 512;
	const height = 256;
	const envData = decodeCompressed(ENV_DATA);
	const data = reconstructHDR(envData, width, height);

	const texture = new DataTexture(data, width, height, RGBAFormat, FloatType);
	texture.mapping = EquirectangularReflectionMapping;
	texture.needsUpdate = true;

	defaultEnvironmentMap = texture;
	return texture;
}
