import { Box3, Vector3, AnimationMixer, Timer, LoopRepeat, LoopOnce } from 'three';
import { GLTFLoader } from 'three/examples/jsm/loaders/GLTFLoader.js';
import { USDLoader } from 'three/examples/jsm/loaders/USDLoader.js';
import { createSpatialContext, initSpatialContext, destroySpatialContext, addObjectToScene, setSpatialStageMode, getSpatialEntityTransform, setSpatialEntityTransform, handleSpatialEnvironmentMap, updateSpatialBackgroundColor, handleSpatialResize } from './spatial-context.js';

export const SUPPORTED_TYPES = Object.freeze([
  'model/gltf-binary',
  'model/gltf+json',
  'model/vnd.usdz+zip'
]);

export const observedAttributes = ['src', 'width', 'height', 'autoplay', 'loop', 'stagemode', 'environmentmap', 'style', 'class'];

// WeakMap for per-element state
const stateMap = new WeakMap();

export function createState() {
  return {
    readyState: 0,
    loadTimeout: null,
    loadGeneration: 0,
    model: null,
    spatialCtx: null,
    mixer: null,
    currentAction: null,
    timer: null,
    duration: 0,
    playbackRate: 1.0,
    paused: true,
    ready: Promise.resolve(),
    readyResolve: null,
    complete: true,
    currentSrc: '',
    colorSchemeHandler: null,
  };
}

export function getState(el) {
  let state = stateMap.get(el);
  if (!state) {
    state = createState();
    stateMap.set(el, state);
  }
  return state;
}

export function measure(el) {
  const rect = el.getBoundingClientRect();
  let width = rect.width;
  let height = rect.height;
  if (!width || !height) {
    width = el.clientWidth || 500;
    height = el.clientHeight || 300;
  }
  return { width, height };
}

export function queueLoad(el) {
  const state = getState(el);
  clearTimeout(state.loadTimeout);
  state.readyState = 1;
  if (!state.readyResolve) {
    state.complete = false;
    state.ready = new Promise((resolve) => {
      state.readyResolve = resolve;
    });
  }
  state.loadTimeout = setTimeout(() => load(el), 0);
}

export function teardownRenderer(el) {
  const state = getState(el);

  if (state.mixer) {
    state.mixer = null;
    state.currentAction = null;
    state.timer = null;
  }

  if (state.loadTimeout) {
    clearTimeout(state.loadTimeout);
    state.loadTimeout = null;
  }

  // Clean up the loaded model from the spatial context, but keep the context alive
  if (state.model) {
    state.model.traverse((child) => {
      if (child.isMesh) {
        if (child.geometry) child.geometry.dispose?.();
        if (child.material) {
          if (Array.isArray(child.material)) {
            child.material.forEach((m) => {
              if (m.map) m.map.dispose?.();
              m.dispose?.();
            });
          } else {
            if (child.material.map) child.material.map.dispose?.();
            child.material.dispose?.();
          }
        }
      }
    });
    state.model = null;
  }
}

export function mirrorSrcAttr(el) {
  const attr = el.getAttribute('src');
  if (!attr) return;
  if (el.src !== attr) {
    el.src = attr;
  }
}

export function updateBackgroundColor(el) {
  const state = getState(el);
  if (state?.spatialCtx) {
    updateSpatialBackgroundColor(el, state.spatialCtx);
  }
}

/**
 * Initialize the spatial context for an element.
 * Called once when the element is first upgraded.
 */
export function initElement(el) {
  const state = getState(el);
  if (!state.spatialCtx) {
    state.spatialCtx = createSpatialContext(el);
    state.spatialCtx.getStageModeForElement = () => getStageMode(el);
    state.spatialCtx.onFirstRender = () => {
      state.complete = true;
      if (state.readyResolve) {
        state.readyResolve(el);
        state.readyResolve = null;
      }
    };
    state.spatialCtx.onFrameTick = () => {
      if (state.mixer && !state.paused) {
        state.timer.update();
        const delta = state.timer.getDelta();
        state.mixer.update(delta);
        if (state.currentAction && state.currentAction.paused && !getLoop(el)) {
          state.paused = true;
          el.dispatchEvent(new Event('ended'));
        }
      }
    };
    initSpatialContext(el, state.spatialCtx);
    updateBackgroundColor(el);
    const initialEnvMap = el.getAttribute('environmentmap');
    if (initialEnvMap) {
      handleSpatialEnvironmentMap(el, state.spatialCtx, initialEnvMap);
    }
    if (typeof window !== 'undefined' && window.matchMedia) {
      state.colorSchemeHandler = () => updateBackgroundColor(el);
      window.matchMedia('(prefers-color-scheme: dark)').addEventListener('change', state.colorSchemeHandler);
    }
  }
}

/**
 * Cleanup the spatial context for an element.
 */
export function cleanupElement(el) {
  const state = getState(el);
  if (state.colorSchemeHandler) {
    if (typeof window !== 'undefined' && window.matchMedia) {
      window.matchMedia('(prefers-color-scheme: dark)').removeEventListener('change', state.colorSchemeHandler);
    }
    state.colorSchemeHandler = null;
  }
  if (state.spatialCtx) {
    destroySpatialContext(el, state.spatialCtx);
    state.spatialCtx = null;
  }
}

export async function load(el) {
  const currentSrc = el.src;
  if (!currentSrc) {
    const state = getState(el);
    state.readyState = 0;
    teardownRenderer(el);
    return;
  }

  const state = getState(el);
  state.readyState = 1;
  state.complete = false;
  state.currentSrc = currentSrc;
  state.loadGeneration++;
  const thisGeneration = state.loadGeneration;
  if (!state.readyResolve) {
    state.ready = new Promise((resolve) => {
      state.readyResolve = resolve;
    });
  }
  teardownRenderer(el);

  try {
    // Fetch and detect format
    const response = await fetch(currentSrc);
    if (state.loadGeneration !== thisGeneration) return;
    if (!response.ok) {
      throw new Error(`Failed to load model: ${response.statusText}`);
    }

    const contentType = response.headers.get('content-type') || '';

    let isUSD = contentType.includes('usdz') || contentType.includes('usd') ||
      currentSrc.endsWith('.usdz') || currentSrc.endsWith('.usd') ||
      currentSrc.endsWith('.usda') || currentSrc.endsWith('.usdc');
    let isGLTF = contentType.includes('gltf') || currentSrc.endsWith('.gltf') || currentSrc.endsWith('.glb');

    let sniffedBuffer = null;

    // For blob/data URLs with no recognisable MIME, sniff magic bytes
    if (!isUSD && !isGLTF) {
      sniffedBuffer = await response.arrayBuffer();
      if (state.loadGeneration !== thisGeneration) return;
      const header = new Uint8Array(sniffedBuffer, 0, Math.min(4, sniffedBuffer.byteLength));
      const magic = String.fromCharCode(...header);
      if (magic === 'glTF') {
        isGLTF = true;
      } else if (magic.startsWith('PK')) {
        isUSD = true;
      }
    }

    let model;
    let animations = [];
    const box = new Box3();
    const center = new Vector3();
    const size = new Vector3();

    if (isUSD) {
      const arrayBuffer = sniffedBuffer || await response.arrayBuffer();
      const usdLoader = new USDLoader();
      const group = usdLoader.parse(arrayBuffer);
      group.updateMatrixWorld(true);
      box.setFromObject(group);
      box.getCenter(center);
      box.getSize(size);
      model = group;
      state.model = model;
      animations = group.animations || [];
    } else {
      // Default to glTF
      const blob = sniffedBuffer
        ? new Blob([sniffedBuffer])
        : await response.blob();
      const objectUrl = URL.createObjectURL(blob);
      const gltfLoader = new GLTFLoader();
      const gltf = await gltfLoader.loadAsync(objectUrl);
      if (state.loadGeneration !== thisGeneration) { URL.revokeObjectURL(objectUrl); return; }
      URL.revokeObjectURL(objectUrl);
      model = gltf.scene;
      state.model = model;
      animations = gltf.animations || [];
      model.updateMatrixWorld(true);
      box.setFromObject(model);
      box.getCenter(center);
      box.getSize(size);
    }

    if (state.spatialCtx) {
      addObjectToScene(el, state.spatialCtx, model, center, size);
      state.spatialCtx.pendingFirstRender = true;
    }

    setupAnimations(el, animations);

    state.readyState = 2;
    el.dispatchEvent(new Event('load'));
  } catch (error) {
    console.error('model polyfill load error', error);
    state.readyState = 0;
    const event = new CustomEvent('error', { detail: error });
    el.dispatchEvent(event);
  }
}

export function play(el) {
  const state = getState(el);
  if (!state || !state.currentAction) return Promise.resolve();
  state.paused = false;
  state.currentAction.paused = false;
  state.timer.reset();
  el.dispatchEvent(new Event('play'));
  return Promise.resolve();
}

export function pause(el) {
  const state = getState(el);
  if (!state || !state.currentAction) return Promise.resolve();
  state.paused = true;
  state.currentAction.paused = true;
  el.dispatchEvent(new Event('pause'));
  return Promise.resolve();
}

export function setCurrentTime(el, value) {
  const state = getState(el);
  if (state && state.currentAction && typeof value === 'number' && isFinite(value)) {
    state.currentAction.time = Math.max(0, Math.min(value, state.duration));
    if (state.paused && state.mixer) {
      state.mixer.update(0);
    }
  }
}

export function getCurrentTime(el) {
  const state = getState(el);
  return state?.currentAction?.time ?? 0;
}

export function setPlaybackRate(el, value) {
  const state = getState(el);
  if (!state) return;
  const coerced = Number(value);
  if (!isFinite(coerced)) return;
  state.playbackRate = coerced;
  if (state.currentAction) {
    state.currentAction.timeScale = coerced;
  }
}

export function getPlaybackRate(el) {
  return getState(el)?.playbackRate ?? 1.0;
}

export function getDuration(el) {
  return getState(el)?.duration ?? 0;
}

export function getPaused(el) {
  return getState(el)?.paused ?? true;
}

export function getLoop(el) {
  return el.hasAttribute('loop');
}

export function setLoop(el, value) {
  if (value) {
    el.setAttribute('loop', '');
  } else {
    el.removeAttribute('loop');
  }
  updateLoopMode(el);
}

export function getAutoplay(el) {
  return el.hasAttribute('autoplay');
}

export function setAutoplay(el, value) {
  if (value) {
    el.setAttribute('autoplay', '');
  } else {
    el.removeAttribute('autoplay');
  }
}

export function getStageMode(el) {
  const attr = el.getAttribute('stagemode');
  return attr || 'none';
}

export function setStageMode(el, value) {
  if (value === 'none' || !value) {
    el.removeAttribute('stagemode');
  } else {
    el.setAttribute('stagemode', value);
  }
  handleStageModeChange(el);
}

export function getEntityTransform(el) {
  const state = getState(el);
  if (!state?.spatialCtx) return new DOMMatrixReadOnly();
  return getSpatialEntityTransform(state.spatialCtx);
}

export function setEntityTransform(el, value) {
  const state = getState(el);
  if (!state?.spatialCtx) return;
  setSpatialEntityTransform(el, state.spatialCtx, value);
}

export function getBoundingBoxCenter(el) {
  const state = getState(el);
  return state?.spatialCtx?.boundingBoxCenter ?? new DOMPointReadOnly(0, 0, 0, 1);
}

export function getBoundingBoxExtents(el) {
  const state = getState(el);
  return state?.spatialCtx?.boundingBoxExtents ?? new DOMPointReadOnly(0, 0, 0, 0);
}

export function handleStageModeChange(el) {
  const state = getState(el);
  if (!state?.spatialCtx) return;
  const mode = getStageMode(el);
  setSpatialStageMode(el, state.spatialCtx, mode);
}

export function handleAttributeChange(el, name, oldValue, newValue) {
  if (oldValue === newValue) return;
  const state = getState(el);
  switch (name) {
    case 'src':
      mirrorSrcAttr(el);
      queueLoad(el);
      break;
    case 'width':
    case 'height':
      if (state?.spatialCtx) {
        handleSpatialResize(el, state.spatialCtx);
      }
      break;
    case 'autoplay':
      if (getAutoplay(el) && state?.currentAction && state.paused) {
        play(el);
      }
      break;
    case 'loop':
      updateLoopMode(el);
      break;
    case 'stagemode':
      handleStageModeChange(el);
      break;
    case 'environmentmap':
      if (state?.spatialCtx) {
        handleSpatialEnvironmentMap(el, state.spatialCtx, newValue || null);
      }
      break;
    case 'style':
    case 'class':
      updateBackgroundColor(el);
      break;
  }
}

function setupAnimations(el, animations) {
  const state = getState(el);
  if (!animations || animations.length === 0) {
    state.duration = 0;
    state.mixer = null;
    state.currentAction = null;
    return;
  }
  state.mixer = new AnimationMixer(state.model);
  state.duration = animations.reduce((max, clip) => Math.max(max, clip.duration), 0);
  const clip = animations[0];
  state.currentAction = state.mixer.clipAction(clip);
  updateLoopMode(el);
  state.currentAction.timeScale = state.playbackRate;
  state.timer = new Timer();
  state.currentAction.paused = true;
  state.currentAction.play();
  if (getAutoplay(el)) {
    play(el);
  }
}

function updateLoopMode(el) {
  const state = getState(el);
  if (!state || !state.currentAction) return;
  if (getLoop(el)) {
    state.currentAction.setLoop(LoopRepeat, Infinity);
  } else {
    state.currentAction.setLoop(LoopOnce, 1);
    state.currentAction.clampWhenFinished = true;
  }
}

export function getSrc(el) {
  const source = el.querySelector('source');
  return source ? source.getAttribute('src') : null;
}

export function setSrc(el, value) {
  let source = el.querySelector('source');
  if (!source) {
    source = document.createElement('source');
    if (el.prepend) {
      el.prepend(source);
    } else {
      el.appendChild(source);
    }
  }
  const next = value ?? '';
  if (source.getAttribute('src') !== next) {
    source.setAttribute('src', next);
  }
  queueLoad(el);
}

export function getWidth(el) {
  const attr = el.getAttribute('width');
  return attr ? Number(attr) : null;
}

export function setWidth(el, value) {
  if (value == null) {
    el.removeAttribute('width');
  } else {
    el.setAttribute('width', String(value));
  }
}

export function getHeight(el) {
  const attr = el.getAttribute('height');
  return attr ? Number(attr) : null;
}

export function setHeight(el, value) {
  if (value == null) {
    el.removeAttribute('height');
  } else {
    el.setAttribute('height', String(value));
  }
}

export function getReady(el) {
  const state = getState(el);
  return state?.ready ?? Promise.resolve();
}

export function getComplete(el) {
  const state = getState(el);
  return state?.complete ?? true;
}

export function getCurrentSrc(el) {
  const state = getState(el);
  return state?.currentSrc ?? '';
}

export function getEnvironmentMap(el) {
  return el.getAttribute('environmentmap') || '';
}

export function setEnvironmentMap(el, value) {
  if (value) {
    el.setAttribute('environmentmap', value);
  } else {
    el.removeAttribute('environmentmap');
  }
  const state = getState(el);
  if (state?.spatialCtx) {
    handleSpatialEnvironmentMap(el, state.spatialCtx, value || null);
  }
}
