import { WebGLRenderer } from 'three';

let sharedRenderer = null;
let offscreenCanvas = null;
const renderCallbacks = new Map();
let sharedAnimationId = null;

export function getSharedRenderer() {
  if (sharedRenderer) return sharedRenderer;

  offscreenCanvas = document.createElement('canvas');
  sharedRenderer = new WebGLRenderer({
    canvas: offscreenCanvas,
    antialias: true,
    alpha: true
  });
  sharedRenderer.setPixelRatio(window.devicePixelRatio);

  return sharedRenderer;
}

export function registerElement(element, renderCallback) {
  renderCallbacks.set(element, renderCallback);
  ensureLoopRunning();
}

export function unregisterElement(element) {
  renderCallbacks.delete(element);

  if (renderCallbacks.size === 0 && sharedAnimationId !== null) {
    cancelAnimationFrame(sharedAnimationId);
    sharedAnimationId = null;
  }
}

export function disposeSharedRenderer() {
  if (sharedAnimationId !== null) {
    cancelAnimationFrame(sharedAnimationId);
    sharedAnimationId = null;
  }
  if (sharedRenderer) {
    sharedRenderer.dispose();
    sharedRenderer = null;
  }
  offscreenCanvas = null;
  renderCallbacks.clear();
}

function ensureLoopRunning() {
  if (sharedAnimationId !== null) return;
  sharedAnimationId = requestAnimationFrame(sharedLoop);
}

function sharedLoop() {
  sharedAnimationId = null;

  const renderer = getSharedRenderer();

  renderCallbacks.forEach((callback, element) => {
    try {
      callback(renderer);
    } catch (e) {
      console.error('Error in render callback for element', element, e);
    }
  });

  if (renderCallbacks.size > 0) {
    sharedAnimationId = requestAnimationFrame(sharedLoop);
  }
}
