import {
  getState, load, queueLoad, mirrorSrcAttr, measure, teardownRenderer,
  initElement, cleanupElement,
  play, pause, setCurrentTime, getCurrentTime, setPlaybackRate, getPlaybackRate,
  getDuration, getPaused, getLoop, setLoop, getAutoplay, setAutoplay,
  getStageMode, setStageMode,
  getEntityTransform, setEntityTransform, getBoundingBoxCenter, getBoundingBoxExtents,
  handleStageModeChange,
  getSrc, setSrc, getWidth, setWidth, getHeight, setHeight,
  getReady, getComplete, getCurrentSrc,
  getEnvironmentMap, setEnvironmentMap,
  handleAttributeChange, observedAttributes,
} from './model-element.js';

const observedAttributeSet = new Set(observedAttributes);

export function applyFallback(el) {
  if (el.__upgraded) return;
  el.__upgraded = true;

  const state = getState(el);

  // Store reference for tests
  el.__modelState = state;

  // Define properties using Object.defineProperties
  Object.defineProperties(el, {
    src: {
      get() { return getSrc(this); },
      set(value) { setSrc(this, value); },
      configurable: true,
    },
    readyState: {
      get() { return getState(this).readyState; },
      configurable: true,
    },
    width: {
      get() { return getWidth(this); },
      set(value) { setWidth(this, value); },
      configurable: true,
    },
    height: {
      get() { return getHeight(this); },
      set(value) { setHeight(this, value); },
      configurable: true,
    },
    ready: {
      get() { return getReady(this); },
      configurable: true,
    },
    complete: {
      get() { return getComplete(this); },
      configurable: true,
    },
    currentSrc: {
      get() { return getCurrentSrc(this); },
      configurable: true,
    },
    duration: {
      get() { return getDuration(this); },
      configurable: true,
    },
    currentTime: {
      get() { return getCurrentTime(this); },
      set(value) { setCurrentTime(this, value); },
      configurable: true,
    },
    playbackRate: {
      get() { return getPlaybackRate(this); },
      set(value) { setPlaybackRate(this, value); },
      configurable: true,
    },
    paused: {
      get() { return getPaused(this); },
      configurable: true,
    },
    loop: {
      get() { return getLoop(this); },
      set(value) { setLoop(this, value); },
      configurable: true,
    },
    autoplay: {
      get() { return getAutoplay(this); },
      set(value) { setAutoplay(this, value); },
      configurable: true,
    },
    stageMode: {
      get() { return getStageMode(this); },
      set(value) { setStageMode(this, value); },
      configurable: true,
    },
    entityTransform: {
      get() { return getEntityTransform(this); },
      set(value) { setEntityTransform(this, value); },
      configurable: true,
    },
    boundingBoxCenter: {
      get() { return getBoundingBoxCenter(this); },
      configurable: true,
    },
    boundingBoxExtents: {
      get() { return getBoundingBoxExtents(this); },
      configurable: true,
    },
    environmentMap: {
      get() { return getEnvironmentMap(this); },
      set(value) { setEnvironmentMap(this, value); },
      configurable: true,
    },
  });

  // Add methods
  el.load = function() { return load(this); };
  el.play = function() { return play(this); };
  el.pause = function() { return pause(this); };

  // Override setAttribute/removeAttribute for synchronous attribute handling.
  // Without this, MutationObserver delivers changes async, so `await ready`
  // resolves with the stale pre-fulfilled promise before src is processed.
  const origSetAttribute = el.setAttribute.bind(el);
  const origRemoveAttribute = el.removeAttribute.bind(el);
  let inOverride = false;

  el.setAttribute = function(name, value) {
    const oldValue = this.getAttribute(name);
    inOverride = true;
    origSetAttribute(name, value);
    inOverride = false;
    const lowerName = name.toLowerCase();
    if (observedAttributeSet.has(lowerName)) {
      handleAttributeChange(this, lowerName, oldValue, String(value));
    }
  };

  el.removeAttribute = function(name) {
    const oldValue = this.getAttribute(name);
    inOverride = true;
    origRemoveAttribute(name);
    inOverride = false;
    const lowerName = name.toLowerCase();
    if (observedAttributeSet.has(lowerName)) {
      handleAttributeChange(this, lowerName, oldValue, null);
    }
  };

  // Set up MutationObserver (port from __modelInit)
  state.mutationObserver = new MutationObserver((mutations) => {
    for (const mutation of mutations) {
      if (mutation.type === 'attributes') {
        if (mutation.target === el && !inOverride) {
          const name = mutation.attributeName;
          if (name === 'src') {
            mirrorSrcAttr(el);
            queueLoad(el);
          } else if (observedAttributeSet.has(name)) {
            handleAttributeChange(el, name, mutation.oldValue, el.getAttribute(name));
          }
        }
        if (mutation.target.nodeName === 'SOURCE' && mutation.attributeName === 'src') {
          queueLoad(el);
        }
      } else if (mutation.type === 'childList') {
        const nodes = [...mutation.addedNodes, ...mutation.removedNodes];
        if (nodes.some((n) => n.nodeType === 1 && n.nodeName === 'SOURCE')) {
          queueLoad(el);
        }
      }
    }
  });

  state.mutationObserver.observe(el, {
    attributes: true,
    attributeOldValue: true,
    childList: true,
    subtree: true,
    attributeFilter: [...observedAttributeSet, 'src'],
  });

  mirrorSrcAttr(el);

  initElement(el);

  // Route any observed attributes already present on the element at upgrade time
  // through handleAttributeChange. The overridden setAttribute only fires for
  // new calls, and the MutationObserver only reports changes — neither covers
  // HTML-declared attributes.
  for (const name of observedAttributes) {
    if (name === 'src' || name === 'environmentmap') continue;
    const value = el.getAttribute(name);
    if (value !== null) {
      handleAttributeChange(el, name, null, value);
    }
  }

  if (el.src) {
    queueLoad(el);
  }
}
