/**
 * Entity transform calculation and application for model-element fallback
 */

import { Matrix4, Vector3, Quaternion } from 'three';

/**
 * CSS pixels per centimeter (96 DPI standard)
 */
export const CSS_PIXELS_PER_CM = 96 / 2.54;

/**
 * Reusable Three.js objects for matrix decomposition (avoids per-frame allocations)
 */
const _threeMatrix = new Matrix4();
const _position = new Vector3();
const _quaternion = new Quaternion();
const _scale = new Vector3();

/**
 * Extract uniform scale factor from a DOMMatrix
 * Assumes uniform scaling (same scale on all axes)
 * @param {DOMMatrixReadOnly} matrix - The matrix to extract scale from
 * @returns {number} The scale factor
 */
export function extractScaleFromMatrix(matrix) {
	return Math.sqrt(
		matrix.m11 * matrix.m11 +
		matrix.m21 * matrix.m21 +
		matrix.m31 * matrix.m31
	);
}

/**
 * Build a transform matrix for positioning a model
 * Matrix order: T(finalPos) * R(pitch, yaw) * S(scale) * T(-center)
 * This rotates around the model's center, then positions it
 *
 * @param {number} scale - Uniform scale factor
 * @param {number} finalZ - Z position after transform
 * @param {{x: number, y: number, z: number, w: number}} quaternion - Rotation quaternion
 * @param {{x: number, y: number, z: number}} center - Model center point
 * @returns {DOMMatrix} The composed transform matrix
 */
export function buildTransformMatrix(scale, finalZ, quaternion, center) {
	const matrix = new DOMMatrix();
	matrix.translateSelf(0, 0, finalZ);

	const { x, y, z, w } = quaternion;
	const rot = new DOMMatrix([
		1 - 2*(y*y + z*z),  2*(x*y + w*z),      2*(x*z - w*y),      0,
		2*(x*y - w*z),      1 - 2*(x*x + z*z),  2*(y*z + w*x),      0,
		2*(x*z + w*y),      2*(y*z - w*x),      1 - 2*(x*x + y*y),  0,
		0,                  0,                  0,                  1,
	]);
	matrix.multiplySelf(rot);

	matrix.scaleSelf(scale, scale, scale);
	matrix.translateSelf(-center.x, -center.y, -center.z);
	return matrix;
}

/**
 * Calculate the default transform for a model to fit within a portal
 *
 * @param {HTMLElement} element - The model element
 * @param {THREE.Vector3} modelSize - Bounding box dimensions
 * @param {THREE.Vector3|{x: number, y: number, z: number}} center - Bounding box center
 * @param {boolean} useSphericalDepth - If true, fit bounding sphere (for orbit mode)
 * @returns {DOMMatrix} The default transform matrix
 */
export function calculateDefaultTransform(element, modelSize, center, useSphericalDepth = false) {
	const rect = element.getBoundingClientRect();
	const portalWidthM = rect.width / CSS_PIXELS_PER_CM / 100;
	const portalHeightM = rect.height / CSS_PIXELS_PER_CM / 100;

	let scale;
	if (useSphericalDepth) {
		// Orbit mode: fit bounding sphere
		const boundingSphereDiameter = modelSize.length();
		const minPortalDim = Math.min(portalWidthM, portalHeightM);
		scale = boundingSphereDiameter > 0 ? minPortalDim / boundingSphereDiameter : 1;
	} else {
		// Non-orbit mode: fit bounding box extents to portal
		const sx = modelSize.x > 0 ? portalWidthM / modelSize.x : Infinity;
		const sy = modelSize.y > 0 ? portalHeightM / modelSize.y : Infinity;
		scale = Math.min(sx, sy) === Infinity ? 1 : Math.min(sx, sy);
	}

	// Calculate translation to center model and position depth
	const tx = -scale * center.x;
	const ty = -scale * center.y;

	let tz;
	if (useSphericalDepth) {
		// Orbit: position so bounding sphere front is at z=0
		const sphereRadius = modelSize.length() / 2;
		tz = -scale * (center.z + sphereRadius);
	} else {
		// Non-orbit: position so front face is at z=0
		const halfDepth = modelSize.z / 2;
		tz = -scale * (center.z + halfDepth);
	}

	const matrix = new DOMMatrix();
	matrix.translateSelf(tx, ty, tz);
	matrix.scaleSelf(scale, scale, scale);

	return matrix;
}

/**
 * Calculate the final Z position for orbit mode (bounding sphere front at z=0)
 * @param {THREE.Vector3} modelSize - Model bounding box size
 * @param {number} scale - Current scale factor
 * @returns {number} The Z position
 */
export function calculateOrbitFinalZ(modelSize, scale) {
	const sphereRadius = modelSize.length() / 2;
	return -scale * sphereRadius;
}

/**
 * Calculate the final Z position for non-orbit mode (front face at z=0)
 * @param {THREE.Vector3} modelSize - Model bounding box size
 * @param {number} scale - Current scale factor
 * @returns {number} The Z position
 */
export function calculateNonOrbitFinalZ(modelSize, scale) {
	const halfDepth = modelSize.z / 2;
	return -scale * halfDepth;
}

/**
 * Apply a DOMMatrixReadOnly transform to a Three.js Object3D
 * Decomposes the matrix into position, quaternion, and scale
 *
 * @param {DOMMatrixReadOnly} matrix - The transform matrix
 * @param {THREE.Object3D} object3D - The Three.js object to transform
 */
export function applyMatrixToObject3D(matrix, object3D) {
	_threeMatrix.set(
		matrix.m11, matrix.m21, matrix.m31, matrix.m41,
		matrix.m12, matrix.m22, matrix.m32, matrix.m42,
		matrix.m13, matrix.m23, matrix.m33, matrix.m43,
		matrix.m14, matrix.m24, matrix.m34, matrix.m44
	);

	_threeMatrix.decompose(_position, _quaternion, _scale);

	object3D.position.copy(_position);
	object3D.quaternion.copy(_quaternion);
	object3D.scale.copy(_scale);
}

export function multiplyQuaternions(a, b) {
	return {
		w: a.w * b.w - a.x * b.x - a.y * b.y - a.z * b.z,
		x: a.w * b.x + a.x * b.w + a.y * b.z - a.z * b.y,
		y: a.w * b.y - a.x * b.z + a.y * b.w + a.z * b.x,
		z: a.w * b.z + a.x * b.y - a.y * b.x + a.z * b.w,
	};
}

export function normalizeQuaternion(q) {
	const len = Math.sqrt(q.x * q.x + q.y * q.y + q.z * q.z + q.w * q.w);
	if (len === 0) { q.x = 0; q.y = 0; q.z = 0; q.w = 1; return; }
	q.x /= len; q.y /= len; q.z /= len; q.w /= len;
}

export function applyOrbitRotation(state, pitchDelta, yawDelta) {
	const halfYaw = yawDelta / 2;
	const qYaw = { x: 0, y: Math.sin(halfYaw), z: 0, w: Math.cos(halfYaw) };
	const halfPitch = pitchDelta / 2;
	const qPitch = { x: Math.sin(halfPitch), y: 0, z: 0, w: Math.cos(halfPitch) };

	state.orbitQuaternion = multiplyQuaternions(qPitch, multiplyQuaternions(qYaw, state.orbitQuaternion));
	normalizeQuaternion(state.orbitQuaternion);
}

export function extractPitch(q) {
	const upY = 1 - 2 * (q.x * q.x + q.z * q.z);
	const upZ = 2 * (q.y * q.z + q.w * q.x);
	return Math.atan2(upZ, upY);
}

/**
 * Reset orbit control state to initial values
 * @param {Object} state - Element state object
 */
export function resetOrbitState(state) {
	state.orbitQuaternion = { x: 0, y: 0, z: 0, w: 1 };
	state.yawVelocity = 0;
	state.pitchVelocity = 0;
}

/**
 * Enable orbit controls on an element
 * @param {HTMLElement} element - The model element
 * @param {Object} state - Element state object
 */
export function enableOrbitControls(element, state) {
	if (!state.canvas) return;

	resetOrbitState(state);

	state.canvas.addEventListener('pointerdown', state.boundPointerDown);
	state.canvas.addEventListener('pointermove', state.boundPointerMove);
	state.canvas.addEventListener('pointerup', state.boundPointerUp);
	state.canvas.addEventListener('pointerleave', state.boundPointerUp);
	state.canvas.addEventListener('pointercancel', state.boundPointerUp);

	state.canvas.style.cursor = 'grab';
	state.canvas.style.touchAction = 'none';
}

/**
 * Disable orbit controls on an element
 * @param {HTMLElement} element - The model element
 * @param {Object} state - Element state object
 */
export function disableOrbitControls(element, state) {
	if (!state.canvas) return;

	state.canvas.removeEventListener('pointerdown', state.boundPointerDown);
	state.canvas.removeEventListener('pointermove', state.boundPointerMove);
	state.canvas.removeEventListener('pointerup', state.boundPointerUp);
	state.canvas.removeEventListener('pointerleave', state.boundPointerUp);
	state.canvas.removeEventListener('pointercancel', state.boundPointerUp);

	state.canvas.style.cursor = 'default';
	state.canvas.style.touchAction = '';
}

/**
 * Handle pointer down event for orbit controls
 * @param {Object} state - Element state object
 * @param {PointerEvent} event - The pointer event
 */
export function onPointerDown(state, event) {
	event.preventDefault();
	state.isDragging = true;
	state.lastPointerX = event.clientX;
	state.lastPointerY = event.clientY;
	state.lastMoveTime = performance.now();

	state.yawVelocity = 0;
	state.pitchVelocity = 0;

	state.canvas.setPointerCapture(event.pointerId);
	state.canvas.style.cursor = 'grabbing';
}

/**
 * Handle pointer move event for orbit controls
 * @param {Object} state - Element state object
 * @param {PointerEvent} event - The pointer event
 */
export function onPointerMove(state, event) {
	if (!state.isDragging) return;

	const currentTime = performance.now();
	const deltaTime = Math.max(currentTime - state.lastMoveTime, 8);

	const deltaX = event.clientX - state.lastPointerX;
	const deltaY = event.clientY - state.lastPointerY;

	applyOrbitRotation(state, deltaY * state.dragSensitivity, deltaX * state.dragSensitivity);

	state.yawVelocity = (deltaX * state.dragSensitivity) * (16 / deltaTime);
	state.pitchVelocity = (deltaY * state.dragSensitivity) * (16 / deltaTime);

	state.lastPointerX = event.clientX;
	state.lastPointerY = event.clientY;
	state.lastMoveTime = currentTime;
}

/**
 * Handle pointer up event for orbit controls
 * @param {Object} state - Element state object
 * @param {PointerEvent} event - The pointer event
 */
export function onPointerUp(state, event) {
	if (!state.isDragging) return;

	state.isDragging = false;

	if (state.canvas) {
		state.canvas.releasePointerCapture(event.pointerId);
		state.canvas.style.cursor = 'grab';
	}
}

/**
 * Update orbit physics (momentum and return-to-center)
 * Called each animation frame when in orbit mode
 * @param {Object} state - Element state object
 */
export function updateOrbitPhysics(state) {
	if (state.isDragging) return;

	state.yawVelocity *= state.orbitDamping;
	state.pitchVelocity *= state.orbitDamping;

	applyOrbitRotation(state, state.pitchVelocity, state.yawVelocity);

	if (Math.abs(state.pitchVelocity) < 0.001) {
		const q = state.orbitQuaternion;
		const tLen = Math.sqrt(q.y * q.y + q.w * q.w);
		if (tLen > 1e-10) {
			const twist = { x: 0, y: q.y / tLen, z: 0, w: q.w / tLen };
			let dot = q.x * twist.x + q.y * twist.y + q.z * twist.z + q.w * twist.w;
			if (dot < 0) { twist.x = -twist.x; twist.y = -twist.y; twist.z = -twist.z; twist.w = -twist.w; }
			const t = state.pitchReturnSpeed;
			state.orbitQuaternion = {
				x: q.x * (1 - t) + twist.x * t,
				y: q.y * (1 - t) + twist.y * t,
				z: q.z * (1 - t) + twist.z * t,
				w: q.w * (1 - t) + twist.w * t,
			};
			normalizeQuaternion(state.orbitQuaternion);
		}
	}
}

/**
 * Update entityTransform based on current orbit state
 * @param {Object} state - Element state object
 * @param {Function} applyEntityTransform - Function to apply the transform
 */
export function updateEntityTransformFromOrbit(state, applyEntityTransform) {
	if (!state.pivotGroup || !state.modelSize) return;

	const center = state.boundingBoxCenter;
	const scale = extractScaleFromMatrix(state.entityTransform);
	const finalZ = calculateOrbitFinalZ(state.modelSize, scale);

	state.entityTransform = buildTransformMatrix(scale, finalZ, state.orbitQuaternion, center);
	applyEntityTransform();
}
